{"content":"1: ﻿using CommandLine;
2: using Microsoft.Extensions.FileSystemGlobbing;
3: using System;
4: using System.Collections.Generic;
5: using System.IO;
6: using System.Linq;
7: using System.Text;
8: using System.Xml.Linq;
9: 
10: namespace CodeCoverageSummary
11: {
12:     internal static class Program
13:     {
14:         private static double lowerThreshold = 0.5;
15:         private static double upperThreshold = 0.75;
16: 
17:         private static int Main(string[] args)
18:         {
19:             return Parser.Default.ParseArguments<CommandLineOptions>(args)
20:                                  .MapResult(o =>
21:                                  {
22:                                      try
23:                                      {
24:                                          // use glob patterns to match files
25:                                          Matcher matcher = new();
26:                                          matcher.AddIncludePatterns(o.Files.ToArray());
27:                                          IEnumerable<string> matchingFiles = matcher.GetResultsInFullPath(".");
28: 
29:                                          if (matchingFiles?.Any() == false)
30:                                          {
31:                                              Console.WriteLine("Error: No files found matching glob pattern.");
32:                                              return -2; // error
33:                                          }
34: 
35:                                          // check files exist
36:                                          foreach (var file in matchingFiles)
37:                                          {
38:                                              if (!File.Exists(file))
39:                                              {
40:                                                  Console.WriteLine($"Error: Coverage file not found - {file}.");
41:                                                  return -2; // error
42:                                              }
43:                                          }
44: 
45:                                          // parse code coverage file
46:                                          CodeSummary summary = new();
47:                                          foreach (var file in matchingFiles)
48:                                          {
49:                                              Console.WriteLine($"Coverage File: {file}");
50:                                              summary = ParseTestResults(file, summary);
51:                                          }
52: 
53:                                          if (summary == null)
54:                                              return -2; // error
55: 
56:                                          summary.LineRate /= matchingFiles.Count();
57:                                          summary.BranchRate /= matchingFiles.Count();
58: 
59:                                          if (summary.Packages.Count == 0)
60:                                          {
61:                                              Console.WriteLine("Parsing Error: No packages found in coverage files.");
62:                                              return -2; // error
63:                                          }
64:                                          else
65:                                          {
66:                                              // hide branch rate if metrics missing
67:                                              bool hideBranchRate = o.HideBranchRate;
68:                                              if (summary.BranchRate == 0 && summary.BranchesCovered == 0 && summary.BranchesValid == 0)
69:                                                  hideBranchRate = true;
70: 
71:                                              // set health badge thresholds
72:                                              if (!string.IsNullOrWhiteSpace(o.Thresholds))
73:                                                  SetThresholds(o.Thresholds);
74: 
75:                                              // generate badge
76:                                              string badgeUrl = o.Badge ? GenerateBadge(summary) : null;
77: 
78:                                              // generate output
79:                                              string output;
80:                                              string fileExt;
81:                                              if (o.Format.Equals("text", StringComparison.OrdinalIgnoreCase))
82:                                              {
83:                                                  fileExt = "txt";
84:                                                  output = GenerateTextOutput(summary, badgeUrl, o.Indicators, hideBranchRate, o.HideComplexity);
85:                                                  if (o.FailBelowThreshold)
86:                                                      output += $"Minimum allowed line rate is {lowerThreshold * 100:N0}%{Environment.NewLine}";
87:                                              }
88:                                              else if (o.Format.Equals("md", StringComparison.OrdinalIgnoreCase) || o.Format.Equals("markdown", StringComparison.OrdinalIgnoreCase))
89:                                              {
90:                                                  fileExt = "md";
91:                                                  output = GenerateMarkdownOutput(summary, badgeUrl, o.Indicators, hideBranchRate, o.HideComplexity);
92:                                                  if (o.FailBelowThreshold)
93:                                                      output += $"{Environment.NewLine}_Minimum allowed line rate is `{lowerThreshold * 100:N0}%`_{Environment.NewLine}";
94:                                              }
95:                                              else
96:                                              {
97:                                                  Console.WriteLine("Error: Unknown output format.");
98:                                                  return -2; // error
99:                                              }
100: 
101:                                              // output
102:                                              if (o.Output.Equals("console", StringComparison.OrdinalIgnoreCase))
103:                                              {
104:                                                  Console.WriteLine();
105:                                                  Console.WriteLine(output);
106:                                              }
107:                                              else if (o.Output.Equals("file", StringComparison.OrdinalIgnoreCase))
108:                                              {
109:                                                  File.WriteAllText($"code-coverage-results.{fileExt}", output);
110:                                              }
111:                                              else if (o.Output.Equals("both", StringComparison.OrdinalIgnoreCase))
112:                                              {
113:                                                  Console.WriteLine();
114:                                                  Console.WriteLine(output);
115:                                                  File.WriteAllText($"code-coverage-results.{fileExt}", output);
116:                                              }
117:                                              else
118:                                              {
119:                                                  Console.WriteLine("Error: Unknown output type.");
120:                                                  return -2; // error
121:                                              }
122: 
123:                                              if (o.FailBelowThreshold && summary.LineRate < lowerThreshold)
124:                                              {
125:                                                  Console.WriteLine($"FAIL: Overall line rate below minimum threshold of {lowerThreshold * 100:N0}%.");
126:                                                  return -2;
127:                                              }
128: 
129:                                              return 0; // success
130:                                          }
131:                                      }
132:                                      catch (Exception ex)
133:                                      {
134:                                          Console.WriteLine($"Error: {ex.GetType()} - {ex.Message}");
135:                                          return -3; // unhandled error
136:                                      }
137:                                  },
138:                                  _ => -1); // invalid arguments
139:         }
140: 
141:         private static CodeSummary ParseTestResults(string filename, CodeSummary summary)
142:         {
143:             if (summary == null)
144:                 return null;
145: 
146:             try
147:             {
148:                 string rss = File.ReadAllText(filename);
149:                 var xdoc = XDocument.Parse(rss);
150: 
151:                 // test coverage for solution
152:                 var coverage = from item in xdoc.Descendants("coverage")
153:                                select item;
154: 
155:                 if (!coverage.Any())
156:                     throw new Exception("Coverage file invalid, data not found");
157: 
158:                 var lineR = from item in coverage.Attributes()
159:                             where item.Name == "line-rate"
160:                             select item;
161: 
162:                 if (!lineR.Any())
163:                     throw new Exception("Overall line rate not found");
164: 
165:                 summary.LineRate += double.Parse(lineR.First().Value);
166: 
167:                 var linesCovered = from item in coverage.Attributes()
168:                                    where item.Name == "lines-covered"
169:                                    select item;
170: 
171:                 if (!linesCovered.Any())
172:                     throw new Exception("Overall lines covered not found");
173: 
174:                 summary.LinesCovered += int.Parse(linesCovered.First().Value);
175: 
176:                 var linesValid = from item in coverage.Attributes()
177:                                  where item.Name == "lines-valid"
178:                                  select item;
179: 
180:                 if (!linesValid.Any())
181:                     throw new Exception("Overall lines valid not found");
182: 
183:                 summary.LinesValid += int.Parse(linesValid.First().Value);
184: 
185:                 var branchR = from item in coverage.Attributes()
186:                               where item.Name == "branch-rate"
187:                               select item;
188: 
189:                 if (branchR.Any())
190:                 {
191:                     summary.BranchRate += double.TryParse(branchR.First().Value, out double bRate) ? bRate : 0;
192: 
193:                     var branchesCovered = from item in coverage.Attributes()
194:                                           where item.Name == "branches-covered"
195:                                           select item;
196: 
197:                     summary.BranchesCovered += int.TryParse(branchesCovered?.First().Value ?? "0", out int bCovered) ? bCovered : 0;
198: 
199:                     var branchesValid = from item in coverage.Attributes()
200:                                         where item.Name == "branches-valid"
201:                                         select item;
202: 
203:                     summary.BranchesValid += int.TryParse(branchesValid?.First().Value ?? "0", out int bValid) ? bValid : 0;
204:                 }
205: 
206:                 // test coverage for individual packages
207:                 var packages = from item in coverage.Descendants("package")
208:                                select item;
209: 
210:                 if (!packages.Any())
211:                     throw new Exception("No package data found");
212: 
213:                 int i = 1;
214:                 foreach (var item in packages)
215:                 {
216:                     CodeCoverage packageCoverage = new()
217:                     {
218:                         Name = string.IsNullOrWhiteSpace(item.Attribute("name")?.Value) ? $"{Path.GetFileNameWithoutExtension(filename)} Package {i}" : item.Attribute("name").Value,
219:                         LineRate = double.Parse(item.Attribute("line-rate")?.Value ?? "0"),
220:                         BranchRate = double.TryParse(item.Attribute("branch-rate")?.Value ?? "0", out double bRate) ? bRate : 0,
221:                         Complexity = double.TryParse(item.Attribute("complexity")?.Value ?? "0", out double complex) ? complex : 0
222:                     };
223:                     summary.Packages.Add(packageCoverage);
224:                     summary.Complexity += packageCoverage.Complexity;
225:                     i++;
226:                 }
227: 
228:                 return summary;
229:             }
230:             catch (Exception ex)
231:             {
232:                 Console.WriteLine($"Parsing Error: {ex.Message} - {filename}");
233:                 return null;
234:             }
235:         }
236: 
237:         private static void SetThresholds(string thresholds)
238:         {
239:             int lowerPercentage;
240:             int upperPercentage = (int)(upperThreshold * 100);
241:             int s = thresholds.IndexOf(" ");
242:             if (s == 0)
243:             {
244:                 throw new ArgumentException("Threshold parameter set incorrectly.");
245:             }
246:             else if (s < 0)
247:             {
248:                 if (!int.TryParse(thresholds, out lowerPercentage))
249:                     throw new ArgumentException("Threshold parameter set incorrectly.");
250:             }
251:             else
252:             {
253:                 if (!int.TryParse(thresholds.AsSpan(0, s), out lowerPercentage))
254:                     throw new ArgumentException("Threshold parameter set incorrectly.");
255: 
256:                 if (!int.TryParse(thresholds.AsSpan(s + 1), out upperPercentage))
257:                     throw new ArgumentException("Threshold parameter set incorrectly.");
258:             }
259:             lowerThreshold = lowerPercentage / 100.0;
260:             upperThreshold = upperPercentage / 100.0;
261: 
262:             if (lowerThreshold > 1.0)
263:                 lowerThreshold = 1.0;
264: 
265:             if (lowerThreshold > upperThreshold)
266:                 upperThreshold = lowerThreshold + 0.1;
267: 
268:             if (upperThreshold > 1.0)
269:                 upperThreshold = 1.0;
270:         }
271: 
272:         private static string GenerateBadge(CodeSummary summary)
273:         {
274:             string colour;
275:             if (summary.LineRate < lowerThreshold)
276:             {
277:                 colour = "critical";
278:             }
279:             else if (summary.LineRate < upperThreshold)
280:             {
281:                 colour = "yellow";
282:             }
283:             else
284:             {
285:                 colour = "success";
286:             }
287:             return $"https://img.shields.io/badge/Code%20Coverage-{summary.LineRate * 100:N0}%25-{colour}?style=flat";
288:         }
289: 
290:         private static string GenerateHealthIndicator(double rate)
291:         {
292:             if (rate < lowerThreshold)
293:             {
294:                 return "❌";
295:             }
296:             else if (rate < upperThreshold)
297:             {
298:                 return "➖";
299:             }
300:             else
301:             {
302:                 return "✔";
303:             }
304:         }
305: 
306:         private static string GenerateTextOutput(CodeSummary summary, string badgeUrl, bool indicators, bool hideBranchRate, bool hideComplexity)
307:         {
308:             StringBuilder textOutput = new();
309: 
310:             if (!string.IsNullOrWhiteSpace(badgeUrl))
311:             {
312:                 textOutput.AppendLine(badgeUrl)
313:                           .AppendLine();
314:             }
315: 
316:             foreach (CodeCoverage package in summary.Packages)
317:             {
318:                 textOutput.Append($"{package.Name}: Line Rate = {package.LineRate * 100:N0}%")
319:                           .Append(hideBranchRate ? string.Empty : $", Branch Rate = {package.BranchRate * 100:N0}%")
320:                           .Append(hideComplexity ? string.Empty : (package.Complexity % 1 == 0) ? $", Complexity = {package.Complexity}" : $", Complexity = {package.Complexity:N4}")
321:                           .AppendLine(indicators ? $", {GenerateHealthIndicator(package.LineRate)}" : string.Empty);
322:             }
323: 
324:             textOutput.Append($"Summary: Line Rate = {summary.LineRate * 100:N0}% ({summary.LinesCovered} / {summary.LinesValid})")
325:                       .Append(hideBranchRate ? string.Empty : $", Branch Rate = {summary.BranchRate * 100:N0}% ({summary.BranchesCovered} / {summary.BranchesValid})")
326:                       .Append(hideComplexity ? string.Empty : (summary.Complexity % 1 == 0) ? $", Complexity = {summary.Complexity}" : $", Complexity = {summary.Complexity:N4}")
327:                       .AppendLine(indicators ? $", {GenerateHealthIndicator(summary.LineRate)}" : string.Empty);
328: 
329:             return textOutput.ToString();
330:         }
331: 
332:         private static string GenerateMarkdownOutput(CodeSummary summary, string badgeUrl, bool indicators, bool hideBranchRate, bool hideComplexity)
333:         {
334:             StringBuilder markdownOutput = new();
335: 
336:             if (!string.IsNullOrWhiteSpace(badgeUrl))
337:             {
338:                 markdownOutput.AppendLine($"![Code Coverage]({badgeUrl})")
339:                               .AppendLine();
340:             }
341: 
342:             markdownOutput.Append("Package | Line Rate")
343:                           .Append(hideBranchRate ? string.Empty : " | Branch Rate")
344:                           .Append(hideComplexity ? string.Empty : " | Complexity")
345:                           .AppendLine(indicators ? " | Health" : string.Empty)
346:                           .Append("-------- | ---------")
347:                           .Append(hideBranchRate ? string.Empty : " | -----------")
348:                           .Append(hideComplexity ? string.Empty : " | ----------")
349:                           .AppendLine(indicators ? " | ------" : string.Empty);
350: 
351:             foreach (CodeCoverage package in summary.Packages)
352:             {
353:                 markdownOutput.Append($"{package.Name} | {package.LineRate * 100:N0}%")
354:                               .Append(hideBranchRate ? string.Empty : $" | {package.BranchRate * 100:N0}%")
355:                               .Append(hideComplexity ? string.Empty : (package.Complexity % 1 == 0) ? $" | {package.Complexity}" : $" | {package.Complexity:N4}" )
356:                               .AppendLine(indicators ? $" | {GenerateHealthIndicator(package.LineRate)}" : string.Empty);
357:             }
358: 
359:             markdownOutput.Append($"**Summary** | **{summary.LineRate * 100:N0}%** ({summary.LinesCovered} / {summary.LinesValid})")
360:                           .Append(hideBranchRate ? string.Empty : $" | **{summary.BranchRate * 100:N0}%** ({summary.BranchesCovered} / {summary.BranchesValid})")
361:                           .Append(hideComplexity ? string.Empty : (summary.Complexity % 1 == 0) ? $" | **{summary.Complexity}**" : $" | **{summary.Complexity:N4}**")
362:                           .AppendLine(indicators ? $" | {GenerateHealthIndicator(summary.LineRate)}" : string.Empty);
363: 
364:             return markdownOutput.ToString();
365:         }
366:     }
367: }
