2: using System;
3: using System.Collections.Generic;
4: 
5: namespace CodeCoverageSummary
6: {
7:     public class CommandLineOptions
8:     {
9:         [Option(longName: "files", Separator = ',', Required = true, HelpText = "A comma separated list of code coverage files to analyse. Also accepts glob patterns.")]
10:         public IEnumerable<string> Files { get; set; }
11: 
12:         [Option(longName: "badge", Required = false, HelpText = "Include a Line Rate coverage badge in the output using shields.io - true or false.", Default = "false")]
13:         public string BadgeString { get; set; }
14: 
15:         public bool Badge => BadgeString.Equals("true", StringComparison.OrdinalIgnoreCase);
16: 
17:         [Option(longName: "fail", Required = false, HelpText = "Fail if overall Line Rate below lower threshold - true or false.", Default = "false")]
18:         public string FailString { get; set; }
19: 
20:         public bool FailBelowThreshold => FailString.Equals("true", StringComparison.OrdinalIgnoreCase);
21: 
22:         [Option(longName: "format", Required = false, HelpText = "Output Format - markdown or text.", Default = "text")]
23:         public string Format { get; set; }
24: 
25:         [Option(longName: "hidebranch", Required = false, HelpText = "Hide Branch Rate values in the output - true or false.", Default = "false")]
26:         public string HideBranchString { get; set; }
27: 
28:         public bool HideBranchRate => HideBranchString.Equals("true", StringComparison.OrdinalIgnoreCase);
29: 
30:         [Option(longName: "hidecomplexity", Required = false, HelpText = "Hide Complexity values in the output - true or false.", Default = "false")]
31:         public string HideComplexityString { get; set; }
32: 
33:         public bool HideComplexity => HideComplexityString.Equals("true", StringComparison.OrdinalIgnoreCase);
34: 
35:         [Option(longName: "indicators", Required = false, HelpText = "Include health indicators in the output - true or false.", Default = "true")]
36:         public string IndicatorsString { get; set; }
37: 
38:         public bool Indicators => IndicatorsString.Equals("true", StringComparison.OrdinalIgnoreCase);
39: 
40:         [Option(longName: "output", Required = false, HelpText = "Output Type - console, file or both.", Default = "console")]
41:         public string Output { get; set; }
42: 
43:         [Option(longName: "thresholds", Required = false, HelpText = "Threshold percentages for badge and health indicators, lower threshold can also be used to fail the action.", Default = "50 75")]
44:         public string Thresholds { get; set; }
45:     }
46: }
